import { Alert } from 'react-native';
import { Client as OAuthClient } from 'oauth-1.0a';
import axios from 'axios';

const authUrl = 'https://your-auth-server.com/auth';
const tokenEndpoint = 'https://your-token-endpoint.com/token';
const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'your-app://callback';

export const loginAsync = async () => {
  try {
    const oauthClient = OAuthClient({
      consumer: {
        key: clientId,
        secret: clientSecret,
      },
    });

    const authData = await axios.get(`${authUrl}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`);
    const code = authData.data;

    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: redirectUri,
    });

    const tokenResponse = await axios.post(tokenEndpoint, params.toString(), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });

    const accessToken = tokenResponse.data.access_token;

    axios.defaults.headers.common['Authorization'] = `Bearer ${accessToken}`;

    try {
      // Call protected API endpoint
      await axios.get('https://your-protected-api.com/data');
    } catch (error) {
      if (error.response.status === 401) {
        const refreshData = await axios.post(tokenEndpoint, new URLSearchParams({
          grant_type: 'refresh_token',
          client_id: clientId,
          client_secret: clientSecret,
          refresh_token: error.response.data.refresh_token,
        }).toString());

        const refreshToken = refreshData.data.access_token;
        axios.defaults.headers.common['Authorization'] = `Bearer ${refreshToken}`;
      } else {
        throw error;
      }
    }

  } catch (error) {
    Alert.alert('Error', 'Failed to authenticate');
  }
};